const body = $('Webhook').item.json.body || $input.item.json;

return {
  userMessage: body.message,
  tenantPhone: body.tenantPhone,
  clientPhone: body.phone,
  pushName: body.pushName || null,
  messageId: body.messageId,
  originalMessage: body.message,
};

// Mock Claude: detecta intencion por palabras clave
const msg = $('Preparar Solicitud Claude').item.json;
const raw = msg.userMessage || '';
const message = raw.toLowerCase();

let intent = 'unknown';
const entities = {};

if (/\b(hola|buenos\s+d[ií]as|buenas\s+(tardes|noches)|saludos|hey)\b/.test(message)) {
  intent = 'greeting';
} else if (/\b(estado|c[oó]mo\s+va|cu[aá]ndo|listo|turno|mi\s+carro|mi\s+moto|mi\s+veh[ií]culo)\b/.test(message)) {
  intent = 'check_status';
  const plateMatch = raw.match(/\b([A-Z]{3}[-\s]?\d{3})\b/i);
  if (plateMatch) entities.plate = plateMatch[1].replace(/[-\s]/g, '').toUpperCase();
} else if (/\b(servicio|precio|cu[aá]nto|ofrecen|tienen|cat[aá]logo|tarifas)\b/.test(message)) {
  intent = 'list_services';
} else if (/\b(historial|mis\s+visitas|visitas\s+anteriores|mis\s+turnos)\b/.test(message)) {
  intent = 'customer_history';
} else if (/\b(agendar|reservar|pedir\s+cita|quiero\s+lavar|quiero\s+turno|nueva\s+cita)\b/.test(message)) {
  intent = 'book_appointment';
} else if (/\b(persona|asesor|operador|ayuda\s+humana|hablar\s+con|agente|humano)\b/.test(message)) {
  intent = 'human_help';
}

return {
  content: [{ text: JSON.stringify({ intent, entities }) }]
};

const claudeResp = $input.item.json;
const prev = $('Preparar Solicitud Claude').item.json;

const VALID_INTENTS = [
  'greeting', 'check_status', 'list_services',
  'customer_history', 'book_appointment', 'human_help', 'unknown'
];

let intent = 'unknown';
let entities = {};

try {
  const rawText = claudeResp.content[0].text.trim();
  const cleaned = rawText.replace(/^```[a-z]*\n?/, '').replace(/```$/, '').trim();
  const parsed = JSON.parse(cleaned);
  intent = parsed.intent || 'unknown';
  entities = parsed.entities || {};
} catch (e) {
  intent = 'unknown';
}

if (!VALID_INTENTS.includes(intent)) {
  intent = 'unknown';
}

if (entities.plate) {
  entities.plate = String(entities.plate).replace(/[^A-Z0-9]/gi, '').toUpperCase();
}

return {
  intent,
  entities,
  clientPhone: prev.clientPhone,
  tenantPhone: prev.tenantPhone,
  pushName: prev.pushName,
  messageId: prev.messageId,
  originalMessage: prev.originalMessage,
};

const name = $json.pushName ? ', ' + $json.pushName : '';
return {
