return {
  reply: '🔍 Para consultar el estado, necesito la *placa del vehículo*.

Ejémplo: *ABC123*

¿Cuál es la placa?'
};

const data = $input.item.json;
const plate = $('Parsear Intencion').item.json.entities.plate;

if (!data.found) {
  return { reply: 'No encontré un turno activo para la placa *' + plate + '*.\n\n¿Deseas agendar un turno? Escríbeme y te ayudo. 😊' };
}

const a = data.appointment;
const statusMap = {
  pending: '⏳ En espera',
  confirmed: '✅ Confirmado',
  in_progress: '🚿 En lavado'
};
const statusText = statusMap[a.status] || a.status;
const fecha = new Date(a.scheduled_at).toLocaleString('es-CO', { dateStyle: 'short', timeStyle: 'short' });

return {
  reply: '🚗 *Estado de tu vehículo*\n\n' +
    'Placa: *' + a.plate + '*\n' +
    'Vehículo: ' + a.brand + ' ' + a.model + '\n' +
    'Servicio: ' + a.service_name + '\n' +
    'Estado: ' + statusText + '\n' +
    'Fecha: ' + fecha +
    (a.staff_name ? '\nResponsable: ' + a.staff_name : '') +
    '\n\n¿Necesitas algo más? 😊'
};

const data = $input.item.json;

if (!data.services || data.services.length === 0) {
  return { reply: 'Actualmente no tenemos servicios configurados. Por favor contáctanos directamente.' };
}

const list = data.services.map(s => {
  const price = s.price ? '$' + Number(s.price).toLocaleString('es-CO') : 'Consultar';
  const dur = s.duration_minutes ? ' (~' + s.duration_minutes + ' min)' : '';
  const desc = s.description ? '\n  ' + s.description : '';
  return '• *' + s.name + '*' + dur + '\n  💰 ' + price + desc;
}).join('\n\n');

return { reply: '🚿 *Nuestros servicios:*\n\n' + list + '\n\n¿Deseas agendar alguno? 😊' };

const data = $input.item.json;

if (!data.found) {
  return { reply: 'No encontré visitas anteriores con tu número. ¿Es tu primera vez con nosotros? ¡Bienvenido! 🎉\n\n¿Deseas agendar tu primer turno?' };
}

const { customer, history } = data;

if (!history || history.length === 0) {
  return { reply: 'Hola *' + customer.name + '*! Aún no tienes visitas registradas. ¿Deseas agendar tu primer turno? 🚗' };
}

const list = history.map(h => {
  const fecha = new Date(h.scheduled_at).toLocaleDateString('es-CO', { dateStyle: 'short' });
  const price = h.price ? ' - $' + Number(h.price).toLocaleString('es-CO') : '';
  return '• ' + fecha + ': *' + h.plate + '* — ' + h.service_name + price;
}).join('\n');

return {
  reply: '📋 *Historial de ' + customer.name + '*\n' +
    'Visitas totales: ' + customer.visit_count + '\n\n' +
    'Últimas visitas:\n' + list + '\n\n¿Deseas agendar un nuevo turno? 😊'
};

return {
  reply: '📅 *Agendar un turno*

Con gusto te ayudo a agendar. Necesito algunos datos:

1. *Placa* del vehículo
2. *Servicio* que deseas (escríbeme "servicios" para ver la lista)
3. *Fecha y hora* preferida

Envíame esa info y listo. 🚿'
};

return {
  reply: '🙋 *Solicitud de asesor*

Hemos recibido tu solicitud. Un asesor se comunicará contigo muy pronto.

Horario de atención: Lunes a Sábado 8am – 6pm

Gracias por tu paciencia. 🙏'
};

return {
  reply: '😊 No entendí bien tu mensaje. Puedo ayudarte con:

1️⃣ Estado de tu vehículo
2️⃣ Ver precios y servicios
3️⃣ Tu historial de visitas
